import { Component, OnInit } from '@angular/core';
import { AlertController, ToastController } from '@ionic/angular';
import { FincaService } from 'src/app/services/finca.service';
import { ClienteService } from 'src/app/services/cliente.service';
import { Finca } from 'src/app/models/finca.model';
import { Cliente } from 'src/app/models/cliente.model';

@Component({
  selector: 'app-fincas',
  templateUrl: './fincas.page.html',
  styleUrls: ['./fincas.page.scss'],
  standalone: false,
})
export class FincasPage implements OnInit {
  fincas: Finca[] = [];
  clientes: Cliente[] = [];

  constructor(
    private svc: FincaService,
    private clienteSvc: ClienteService,
    private alert: AlertController,
    private toast: ToastController
  ) {}

  ngOnInit() {
    this.clienteSvc.getActivos().subscribe(d => this.clientes = d);
    this.cargar();
  }

  cargar(event?: any) {
    this.svc.getAll().subscribe(d => { this.fincas = d; event?.target?.complete(); });
  }

  nombreCliente(id: string | number): string {
    return this.clientes.find(c => c.id === id)?.nombre || '';
  }

  async abrirForm(finca?: Finca) {
    const esEditar = !!finca;
    const a = await this.alert.create({
      header: esEditar ? 'Editar Finca' : 'Nueva Finca',
      inputs: [
        { name: 'nombre', type: 'text', placeholder: 'Nombre', value: finca?.nombre || '' },
        ...this.clientes.map(c => ({
          name: 'idCliente',
          type: 'radio' as const,
          label: c.nombre,
          value: c.id,
          checked: finca?.idCliente === c.id
        }))
      ],
      buttons: [
        { text: 'Cancelar', role: 'cancel' },
        {
          text: 'Guardar',
          handler: (data) => {
            if (!data.nombre?.trim()) return false;
            if (esEditar) {
              this.svc.update(finca!.id!, { nombre: data.nombre }).subscribe(() => this.cargar());
            } else {
              this.svc.create({ nombre: data.nombre, idCliente: Number(data.idCliente), estado: 'activo' }).subscribe(() => this.cargar());
            }
            return true;
          }
        }
      ]
    });
    await a.present();
  }

  async toggleEstado(f: Finca) {
    const nuevoEstado = f.estado === 'activo' ? 'inactivo' : 'activo';
    this.svc.update(f.id!, { estado: nuevoEstado }).subscribe(() => this.cargar());
  }

  async eliminar(f: Finca) {
    const a = await this.alert.create({
      header: 'Confirmar',
      message: `¿Eliminar "${f.nombre}"?`,
      buttons: [
        { text: 'Cancelar', role: 'cancel' },
        {
          text: 'Eliminar',
          handler: () => {
            this.svc.delete(f.id!).subscribe(async () => {
              this.cargar();
              (await this.toast.create({ message: 'Eliminado.', duration: 2000, position: 'top', color: 'success' })).present();
            });
          }
        }
      ]
    });
    await a.present();
  }
}
